<template>
  <div class="components-resource">
    <!-- header -->
    <div class="resource-header stuck">
      <span class="arrow-icon ellipsis-1" :class="{'active':expandAll}" @click="collapseAllClickHandler()">
        <i v-if="checkHasSomeChild" class="fa-solid fa-angles-down"></i> {{ headerTitle }}
      </span>
    </div>
    <!-- 房型 -->
    <template v-for="(v, i) in dataList">
      <b-form-row :key="i" class="resource-type">
        <b-col cols="12" class="resource-item pr-0">
          <b-form-row>
            <b-col class="label pl-0" :data-id="v.id">
              <span :id="`name_${i}`" class="arrow-icon ellipsis-1" :class="{'active':v.active}" @click="collapseClickHandler(i)">
                <i v-if="hasChild(v)" class="fa-solid fa-angle-down"></i>
                <span :class="{'pl-1':!isMobile}"><b>{{ v.name }}</b></span>
                <b-tooltip
                  :target="`name_${i}`"
                  custom-class="b-tooltip-class"
                  placement="topright"
                  triggers="hover"
                  boundary="document"
                >
                  {{ v.name }}
                </b-tooltip>
              </span>
              <template v-if="v.layout&&v.layout.wait&&v.layout.wait.waitRowspan>0">
                <b-badge :id="`badge_${i}`" class="b-badge-class" @click="collapseWaitClickHandler(i)">
                  {{ v.layout.wait.waitRowspan }}
                </b-badge>
                <b-tooltip
                  :target="`badge_${i}`"
                  custom-class="b-tooltip-class"
                  placement="topright"
                  triggers="hover"
                  boundary="document"
                >
                  {{ waitTitle }}
                </b-tooltip>
              </template>
            </b-col>
            <template v-if="v.extend">
              <b-col cols="auto" class="p-0">
                <small>{{ v.extend }}</small>
              </b-col>
            </template>
          </b-form-row>
        </b-col>
      </b-form-row>
      <!-- 待排房 -->
      <b-form-row v-if="showWait" :key="`contents_wait_${i}`" class="contents-row collapse-wait" :class="{'active': v.active&&v.waitActive}">
        <b-col cols="12" class="resource-children-item" :class="['rowspan-1', `rowspan-${parseLayoutInfo(v, 'wait')}`]">
          <b-form-row>
            <b-col class="label">
              <span :class="{'pl-2':!isMobile}">{{ waitTitle }}</span>
            </b-col>
          </b-form-row>
        </b-col>
      </b-form-row>
      <!-- 房間 -->
      <b-form-row v-for="(v1, i1) in v.children" :key="`contents_${i}_${i1}`" class="contents-row collapse" :class="{'active': v.active}">
        <b-col cols="12" class="resource-children-item">
          <b-form-row>
            <b-col class="label" :data-id="v1.id" :data-rowspan="parseLayoutInfo(v, v1.id)">
              <span :class="['text-left ellipsis-1', {'pl-2':!isMobile}]">{{ v1.name }}</span>
            </b-col>
            <b-col v-if="v1.disabled" cols="auto" class="pr-0">
              <i class="fa-solid fa-ban"></i>
            </b-col>
            <template v-if="hasSlot('slot-resource-info')">
              <b-col cols="auto">
                <slot name="slot-resource-info" :scope="v1"></slot>
              </b-col>
            </template>
          </b-form-row>
        </b-col>
      </b-form-row>
    </template>
  </div>
</template>

<script>
export default {
  name: 'ComponentsResource',
  components: {},
  props: {
    debug: {
      type: Boolean,
      default: false
    },
    headerTitle: {
      type: String,
      default: 'Header Title'
    },
    showWait: {
      type: Boolean,
      default: true
    },
    waitTitle: {
      type: String,
      default: 'Wait Title'
    },
    data: {
      type: Array,
      default() {
        return []
      }
    }
  },
  data() {
    return {
      isMobile: window.innerWidth < 992,
      pageLoad: false,
      expandAll: true
    }
  },
  computed: {
    checkHasSomeChild() {
      return this.dataList
        .map(c => c.children && c.children.length)
        .filter(c => c)
        .reduce((a, b) => a + b, 0)
    },
    dataList: {
      get() {
        const result = this.data.map(c => ({
          ...c,
          active: typeof c.active === 'undefined' ? true : c.active,
          waitActive: typeof c.waitActive === 'undefined' ? true : c.waitActive
        }))
        return [
          ...result
        ]
      },
      set(value) {
        this.$emit('update:data', value)
      }
    },
    isAllExpand() {
      return !this.dataList.some(c => !c.active)
    },
    isAllCollapse() {
      return !this.dataList.some(c => c.active)
    }
  },
  mounted() {
    // collapse active default
    const result = this.dataList.map(c => ({
      ...c,
      active: typeof c.active === 'undefined' ? true : c.active
    }))
    if (!this.pageLoad) {
      this.pageLoad = true
      this.dataList = result
    }

    this._resizeHandler = () => {
      this.isMobile = window.innerWidth < 992
    }
    window.addEventListener('resize', this._resizeHandler)
    this._resizeHandler()
  },
  beforeDestroy() {
    if (this._resizeHandler) {
      window.removeEventListener('resize', this._resizeHandler)
    }
  },
  methods: {
    hasChild(data) {
      return data && Array.isArray(data.children) && data.children.length
    },
    hasSlot(name = 'default') {
      return !!this.$slots[name] || !!this.$scopedSlots[name]
    },
    collapseAllClickHandler(index = 0) {
      if (index === 0) {
        this.expandAll = !this.expandAll
      }
      if (index < this.dataList.length) {
        this.dataList[index].active = this.expandAll
        this.dataList = [...this.dataList]
        setTimeout(() => {
          this.collapseAllClickHandler(index += 1)
        }, 100)
      }
    },
    collapseWaitClickHandler(index) {
      const result = this.dataList
      result[index].waitActive = !result[index].waitActive
      this.dataList = result
    },
    collapseClickHandler(index) {
      const result = this.dataList
      result[index].active = !result[index].active
      if (this.hasChild(result[index])) {
        this.dataList = result

        if (this.isAllCollapse) {
          this.expandAll = false
        }
        if (this.isAllExpand) {
          this.expandAll = true
        }
      }
    },
    parseLayoutInfo(data, value) {
      return data?.layout?.[value]?.rowspan || 1
    }
  }
}
</script>

