<template>
  <div v-show="visibleValue" :id="key" class="components-context-menu">
    <b-overlay spinner-variant="primary" :show="loading">
      <div class="components-context-menu-content">
        <button class="close" @click="visibleValue=false">
          ×
        </button>
        <slot></slot>
      </div>
    </b-overlay>
  </div>
</template>

<script>
export default {
  name: 'ComponentsContextMenu',
  props: {
    visible: {
      type: Boolean,
      default: false
    },
    loading: {
      type: Boolean,
      default: false
    },
    options: {
      type: Object,
      default() {
        return {
          // width: '200px',
          // top: '100px',
          // left: '100px'
        }
      }
    }
  },
  data() {
    return {
      key: `id_${Date.now()}`
    }
  },
  computed: {
    visibleValue: {
      get() {
        return this.visible
      },
      set(value) {
        this.$emit('update:visible', value)
      }
    }
  },
  watch: {
    options: {
      handler() {
        const options = this.options || {}
        const el = document.querySelector(`#${this.key}`)
        if (el) {
          setTimeout(() => {
            Object.entries(options).forEach(([key, val]) => {
              let value = val
              switch (key) {
                case 'top':
                  value = `${val - el.clientHeight - 8}px`
                  break
                case 'left':
                  value = `${val - 25}px`
                  break
              }
              el.style[key] = value
            })
          })
        }
      },
      deep: true,
      immediate: false
    }
  },
  methods: {}
}
</script>

