<template>
  <div class="components-calendar container-fluid">
    <b-overlay spinner-variant="primary" :show="loading">
      <div class="header">
        <slot name="slot-toolbar-top"></slot>

        <b-form-row v-if="showToolbar" :class="['calendar-header-toolbar-top', 'pb-1', {'small':!isMobile}]">
          <b-col cols="auto">
            <SwitchButton v-model="options.allowEdit" size="md">
              {{ i18n('addnew_onder') }}
            </SwitchButton>
          </b-col>
          <b-col cols="auto">
            <SwitchButton v-model="options.allowContinuous" size="md">
              {{ i18n('continuous_display') }}
            </SwitchButton>
          </b-col>
          <b-col cols="auto">
            <SwitchButton v-model="options.allowAutoAssign" size="md">
              {{ i18n('autoassign_room') }}
            </SwitchButton>
          </b-col>
        </b-form-row>

        <b-form-row>
          <b-col cols="12" md="auto" class="pb-2">
            <b-form-row>
              <b-col v-if="!isViewMonth" cols="auto">
                <b-button
                  :size="getSize()"
                  variant="outline-light"
                  @click="viewTodayClickHandler"
                >
                  {{ i18n('today') }}
                </b-button>
              </b-col>
              <b-col cols="auto" class="ml-auto">
                <b-button-group class="w-100">
                  <span v-if="isViewMonth" :class="['btn', 'btn-outline-light', `btn-${getSize()}`]">
                    {{ currentMonth }}
                  </span>
                  <input v-else v-model="selected.startDate" type="date" class="form-control date-picker">

                  <b-button class="mxw-60px" :size="getSize()" variant="outline-light" @click="viewShiftClickHandler()">
                    <i class="fa-solid fa-angle-left"></i>
                  </b-button>
                  <b-button class="mxw-60px" :size="getSize()" variant="outline-light" @click="viewShiftClickHandler(true)">
                    <i class="fa-solid fa-angle-right"></i>
                  </b-button>
                </b-button-group>
              </b-col>
            </b-form-row>
          </b-col>
          <b-col cols="auto" class="pb-2">
            <b-button-group>
              <b-button
                v-for="(v, i) in views"
                :key="i"
                :size="getSize()"
                variant="outline-primary"
                :class="{'active': v.active}"
                @click="viewsClickHandler(v.value)"
              >
                <template v-if="v.value === 'month'">
                  {{ i18n(v.value) }}
                </template>
                <template v-else>
                  {{ v.value }}{{ i18n('day') }}
                </template>
              </b-button>
            </b-button-group>
          </b-col>
          <b-col class="right-middle pb-2">
            <slot name="slot-toolbar-right"></slot>
          </b-col>
        </b-form-row>
      </div>
      <b-row class="main">
        <div class="components-calendar-menu">
          <resource-menu
            :header-title="headerText"
            :show-wait="showWait"
            :wait-title="waitText"
            :data.sync="resourceData"
          >
            <template v-if="hasSlot('slot-resource-info')" #slot-resource-info="{ scope }">
              <slot name="slot-resource-info" :scope="scope"></slot>
            </template>
          </resource-menu>
        </div>
        <div class="components-calendar-main">
          <scheduler
            ref="scheduler"
            :today="today"
            :show-wait="showWait"
            :margin-top="marginTop"
            :locale="locale"
            :range="dateRange"
            :holiday="holiday"
            :resource.sync="resourceData"
            :stock.sync="stockData"
            :items.sync="itemList"
            :allow-change-date="allowChangeDate"
            :allow-change-type="allowChangeType"
            :allow-edit="allowEdit"
            :allow-continuous="allowContinuous"
            :allow-auto-assign="allowAutoAssign"
            @click="itemClickHandler"
            @assign="itemAssignClickHandler"
            @drop="dropHandler"
          >
            <template v-if="hasSlot('slot-item-info')" #slot-item-info="{ scope }">
              <slot name="slot-item-info" :scope="scope"></slot>
            </template>
            <template v-else #slot-item-info="{ scope }">
              <div>
                <!-- {{ scope.item_id }} -->
                <span
                  v-if="scope.payment_status"
                  :class="[
                    'pay_status_icon',
                    scope.payment_status,
                    {
                      'black': !scope.assign
                    }
                  ]"
                ></span>
                <span v-if="scope.title">
                  {{ scope.title }}
                  <template v-if="scope.nan"><sup>{{ i18n('note') }}{{ scope.nan }}</sup></template>
                </span>
                <span v-else>{{ scope.start }}</span>
                <br>
                <span>{{ scope.source }}<span v-if="scope.order_from"> ({{ scope.order_from }})</span></span>
              </div>
            </template>

            <template v-if="hasSlot('slot-item-stock')" #slot-item-stock="{ scope }">
              <slot name="slot-item-stock" :scope="scope"></slot>
            </template>
          </scheduler>
        </div>
      </b-row>
    </b-overlay>
  </div>
</template>

<script>
import $dayjs from 'dayjs'
import 'dayjs/locale/en'
import 'dayjs/locale/zh-tw'
import 'dayjs/locale/ja'

import splitInit from '../modules/splitInit'
import $dict from '../modules/dict'
import $util from '../modules/util'
import scheduler from './scheduler.vue'
import resourceMenu from './resourceMenu.vue'
import SwitchButton from '../SwitchButton.vue'

const watchList = {}
;(['items', 'options.view', 'options.allowEdit', 'options.allowContinuous', 'options.allowAutoAssign']).forEach(c => {
  watchList[c] = function(val) {
    switch(c) {
      case 'items':
      case 'options.view':
        break
      default:
        $util.cookies.set({
          key: c.split('.')[1],
          val
        })
        break
    }
    this.fixOrderSortError()
  }
})

export default {
  name: 'ComponentsCalendar',
  components: {
    scheduler,
    resourceMenu,
    SwitchButton
  },
  props: {
    loading: {
      type: Boolean,
      default: false
    },
    today: {
      type: [Object, Number, String],
      default() {
        return Date.now()
      }
    },
    resource: {
      type: Array,
      default() {
        return [
          // {
          //   id: 1,
          //   name: 'RoomType',
          //   children: [
          //     {
          //      id: 10,
          //       name: 'room',
          //     }
          //   ]
          // }
        ]
      }
    },
    stock: {
      type: Object,
      default() {
        return {}
      }
    },
    items: {
      type: Array,
      default() {
        return []
      }
    },
    holiday: {
      type: Array,
      default() {
        return []
      }
    },
    options: {
      type: Object,
      default() {
        return {}
      }
    }
  },
  data() {
    return {
      isMobile: window.innerWidth < 992,
      defaultData: {
        // hotkey
        hotkey: true,
        // calendar
        defaultDate: this.now().format(this.format),
        defaultView: 7,
        previewDay: 1,
        locale: 'en', // en|tw
        views: [3, 7, 15, 'month'],
        format: 'YYYY-MM-DD'
        // // resource
        // headerTitle: 'Header Title',
        // waitTitle: 'Wait Title'
      },
      selected: {
        startDate: this.now().format(this.format),
        count: 7
      },
      updateViewEvent: null
    }
  },
  computed: {
    dict() {
      return $dict[this.lang] || $dict.en
    },
    stockData: {
      get() {
        return this.stock
      },
      set(value) {
        this.$emit('update:stock', value)
      }
    },
    itemList: {
      get() {
        return this.items
      },
      set(value) {
        this.$emit('update:items', value)
      }
    },
    resourceData: {
      get() {
        return this.resource
      },
      set(value) {
        this.$emit('update:resource', value)
      }
    },
    optionsData: {
      get() {
        return {
          ...this.defaultData,
          ...this.options
        }
      },
      set(value) {
        this.$emit('update:options', value)
      }
    },
    viewCountDefault() {
      const views = this.defaultData.views
      const count = this.optionsData?.view?.count
      return typeof count !== 'undefined'
        ? views.includes(count)
          ? count
          : views[1]
        : views[1]
    },
    isViewMonth() {
      return this.selected.count === 'month'
    },
    currentMonth() {
      return $dayjs(this.selected.startDate).format('MMM')
    },
    showWait() {
      return typeof this.optionsData?.showWait !== 'undefined'
        ? this.optionsData.showWait
        : true
    },
    showToolbar() {
      return typeof this.optionsData?.showToolbar !== 'undefined'
        ? this.optionsData.showToolbar
        : true
    },
    marginTop() {
      return Number(this.optionsData?.marginTop) || 0
    },
    allowChangeDate() {
      return !!this.optionsData?.allowChangeDate
    },
    allowChangeType() {
      return !!this.optionsData?.allowChangeType
    },
    allowEdit() {
      return this.showToolbar
        ? !!this.optionsData?.allowEdit
        : true
    },
    allowContinuous() {
      return this.showToolbar
        ? !!this.optionsData?.allowContinuous
        : true
    },
    allowAutoAssign() {
      return this.showToolbar
        ? !!this.optionsData?.allowAutoAssign
        : true
    },
    allowHotkey() {
      return !!this.optionsData?.hotkey
    },
    headerText() {
      return this.optionsData?.headerTitle
    },
    waitText() {
      return this.optionsData?.waitTitle
    },
    format() {
      return this.optionsData?.format
    },
    views() {
      const list = this.optionsData?.views || []
      return list.map(v => ({
        active: this.selected.count === v,
        value: v
      }))
    },
    lang() {
      return $util.formatLang(this.locale)
    },
    locale() {
      return this.optionsData?.locale || 'en'
    },
    previewDay() {
      return (this.optionsData?.previewDay || 0) * -1
    },
    dateRange() {
      const value = this.selected.startDate
      const count = this.selected.count || 1
      const start = this.isViewMonth
        ? $dayjs(this.selected.startDate).startOf('month').format(this.format)
        : $dayjs(value).format(this.format)
      const end = this.isViewMonth
        ? $dayjs(this.selected.startDate).endOf('month').format(this.format)
        : $dayjs(value).add(count - 1, 'days').format(this.format)

      return { start, end }
    },
    // vCaleLocale() {
    //   let thisLang = this.locale || 'en-US'
    //   switch (thisLang.toLowerCase()) {
    //     case 'ja_jp':
    //     case 'ja-jp':
    //     case 'jajp':
    //     case 'ja':
    //     case 'jp':
    //       thisLang = 'ja'
    //       break
    //     case 'zh_tw':
    //     case 'zh-tw':
    //     case 'zhtw':
    //     case 'tw':
    //       thisLang = 'zh-TW'
    //       break
    //     case 'en_us':
    //     case 'en-us':
    //     case 'enus':
    //     case 'en':
    //     default:
    //       thisLang = 'en-US'
    //       break
    //   }
    //   return thisLang
    // },
    schedulerRef() {
      return this.$refs?.scheduler || {}
    }
  },
  watch: {
    ...watchList,
    locale() {
      this.dayJsLocale(this.locale)
    },
    selected: {
      handler() {
        let { count, startDate: start, end } = this.selected
        if (this.isViewMonth) {
          start = $dayjs(start).startOf('month').format(this.format)
          end = $dayjs(start).endOf('month').format(this.format)
          count = $dayjs(end).diff($dayjs(start), 'days') + 1
        }
        else {
          start = $dayjs(start).format(this.format)
          end = $dayjs(start).add(count - 1, 'days').format(this.format)
        }

        const view = {
          start,
          end,
          count
        }
        this.optionsData = {
          ...this.optionsData,
          view
        }

        // change event
        if (this.debounceChangeEvent) {
          clearTimeout(this.debounceChangeEvent)
        }
        this.debounceChangeEvent = setTimeout(() => {
          this.$emit('change', view)
          delete this.debounceChangeEvent
        }, 100)
      },
      immediate: false,
      deep: true
    },
    'selected.count': {
      handler() {
        $util.cookies.set({
          key: 'view-count',
          val: this.selected.count
        })
      },
      immediate: false,
      deep: true
    }
  },
  async mounted() {
    this.globeEventbind()
    this.getSettingCache()
    await this.$nextTick()
    this.init()

    this._scrollToToday = () => {
      const main = document.querySelector('.components-calendar-main .components-scheduler')
      const today = document.querySelector('.components-calendar-main .components-scheduler .dates .today')
      if (main && today) {
        const { width, x } = today.getBoundingClientRect()
        main.scrollTo(x - (width * 3.5), 0)
      }
    }
    window.scrollToToday = this._scrollToToday
  },
  beforeDestroy() {
    if (this._resizeHandler) {
      window.removeEventListener('resize', this._resizeHandler)
    }
    if (this._keydownHandler) {
      document.removeEventListener('keydown', this._keydownHandler)
    }
    clearTimeout(this._fixOrderSortTimeout)
    clearTimeout(this.debounceChangeEvent)
    delete window.scrollToToday
  },
  methods: {
    fixOrderSortError() {
      clearTimeout(this._fixOrderSortTimeout)
      this._fixOrderSortTimeout = setTimeout(async() => {
        await this.$nextTick()
        document.querySelectorAll('.components-calendar-main [data-type="wait"]').forEach(v => {
          v.querySelectorAll('[data-type="item"]').forEach((v1, i1) => {
            if (![...v1.classList].includes('done')){
              v1.classList.remove(...[...Array(100)].map((v, i) => `item-order-${i + 1}`))
            }
            const c = [`item-order-${i1 + 1}`, 'done']
            const uids = v1.getAttribute('data-_uids')
            document.querySelectorAll(`[data-_uids="${uids}"]:not(.done)`).forEach(v2 => {
              v2.classList.remove(...[...Array(100)].map((v, i) => `item-order-${i + 1}`))
              v2.classList.add(...c)
            })
          })
        })
        document.querySelectorAll('.done').forEach(v => v.classList.remove('done'))
        this._fixOrderSortTimeout = null
      }, 10)
    },
    hasSlot(name = 'default') {
      return !!this.$slots[name] || !!this.$scopedSlots[name]
    },
    deepCopy(value) {
      return JSON.parse(JSON.stringify(value))
    },
    init() {
      this.selected.count = this.viewCountDefault
      this.dayJsLocale(this.locale)
      splitInit({
        el: ['.components-calendar-menu', '.components-calendar-main'],
        minSize: [200, 20]
      })

      this.viewTodayClickHandler(this.optionsData.defaultDate)
    },
    globeEventbind() {
      this._resizeHandler = () => {
        this.isMobile = window.innerWidth < 576
      }
      window.addEventListener('resize', this._resizeHandler)

      if (this.allowHotkey) {
        this._keydownHandler = (e) => {
          const key = e.which || e.keyCode
          const ctrl = e.ctrlKey ? e.ctrlKey : key === 17
          const meta = e.metaKey

          const ctrlKey = meta || ctrl
          switch ([ctrlKey, key].join()) {
            case 'true,37': // ctrl+left
              e.preventDefault()
              this?.viewShiftClickHandler()
              break
            case 'true,39': // ctrl+right
              e.preventDefault()
              this?.viewShiftClickHandler(true)
              break
            case 'true,38': // ctrl+up
            case 'true,40': // ctrl+down
              e.preventDefault()
              this?.viewTodayClickHandler()
              break
          }
        }
        document.addEventListener('keydown', this._keydownHandler)
      }
    },
    getSettingCache() {
      const opt = this.deepCopy(this.optionsData)
      ;(['allowEdit', 'allowContinuous', 'allowAutoAssign']).forEach(v => {
        const val = $util.cookies.get(v)
        opt[v] = val === 'true' || val === '1'
      })
      const count = +$util.cookies.get('view-count') || +this.optionsData.view || +this.options?.view?.count || 7
      this.selected.count = count

      this.optionsData = opt
    },
    getSize() {
      return this.isMobile ? '' : 'sm'
    },
    now(value) {
      return $dayjs(value).isValid() ? $dayjs(value) : $dayjs()
    },
    dayJsLocale(lang) {
      let thisLang = lang || 'en'
      switch (thisLang.toLowerCase()) {
        case 'zh_tw':
        case 'zh-tw':
        case 'zhtw':
        case 'tw':
          thisLang = 'zh-tw'
          break
        default:
          break
      }
      $dayjs.locale(thisLang)
    },
    i18n(value) {
      return this.dict[value]
    },
    viewsClickHandler(value) {
      if (value !== this.selected.view) {
        this.selected.count = value
      }
    },
    viewShiftClickHandler(value) {
      if (this.isViewMonth) {
        const month = (value ? 1 : -1)
        this.selected.startDate = $dayjs(this.selected.startDate).add(month, 'month').startOf('month').format(this.format)
      }
      else {
        const count = this.selected.count
        const days = (value ? 1 : -1) * count
        const range = this.dateRange
        range.end = $dayjs(range.start).add(days, 'days').format(this.format)
        this.selected.startDate = range.end
      }
    },
    viewTodayClickHandler(value) {
      const sdate = this.now(value).add(this.previewDay, 'days').format(this.format)
      this.selected.startDate = sdate
    },
    //
    itemClickHandler(value) {
      // const { date, room, num } = value
      this.$emit('click', value)
    },
    itemAssignClickHandler(value) {
      this.$emit('assign', value)
    },
    dropHandler(value) {
      this.$emit('drop', value)
    }
  }
}
</script>

